above code is a orm model function execute in a thread，the scheduler is a TornadoScheduler which is in cronscheduler module, following is cronscheduler.py:

`import logging
from apscheduler.jobstores.sqlalchemy import SQLAlchemyJobStore
from apscheduler.schedulers.base import STATE_STOPPED, STATE_PAUSED, STATE_RUNNING
from apscheduler.schedulers.tornado import TornadoScheduler
from concurrent.futures import ThreadPoolExecutor, ProcessPoolExecutor
from tzlocal import get_localzone
tz = get_localzone()

jobstores = {}
executors = {}
job_defaults = {}

__scheduler = None

def get_scheduler():
    global __scheduler
    if __scheduler is None:
        __scheduler = TornadoScheduler(jobstores=jobstores, executors=executors, job_defaults=job_defaults, timezone=tz)

    return __scheduler

def init(options):
    global jobstores, executors, job_defaults
    jobstores.update(
        {
            'default': SQLAlchemyJobStore(url=options.sql_connection)
        }
    )
    executors.update(
        {
            'default': {'type': 'threadpool', 'max_workers': options.thread_pool},
            'processpool': {'type': 'processpool', 'max_workers': options.process_pool}
        }
    )
    job_defaults.update(
        {
            'coalesce': options.coalesce,
            'max_instances': options.max_instances
        }
    )

    sched = get_scheduler()
    if sched.state == STATE_STOPPED:
        sched.start()
    if sched.state == STATE_PAUSED:
        sched.resume()

def stop():
    global __scheduler
    if __scheduler is not None:
        if __scheduler.state == STATE_RUNNING:
            __scheduler.shutdown()


from clouds.cron.service_client_manager import get_service_client_mananger

def notify_job(action, succ_callback, fail_callback, *args, **kwargs):
    '''
        notify subscriber to execute cron job
    '''

    print '########### notify #########', action


def call_service_job(action, succ_callback, fail_callback):
    '''
    call other service to execute the cron job
    '''
    print '########## call service %s ########' % action['service'], action['url']
    try:
        ret = get_service_client_mananger().get_service_client(action['service']).\
            request(action['method'], action['url'], succ_callback, fail_callback, body=action['data'], sync=True)
        # call service cron job status succ log
    except Exception as e:
        logging.warning('Exception: Call Service %s %s failed: %s', action['method'], action['url'], str(e))
        # call service cron job status fail log
